 77→        StringBuilder sb = new StringBuilder("{");
 78→        sb.append("\"title\":\"").append(title).append("\"");
 79→        if (description != null) {
 80→            sb.append(",\"description\":\"").append(description).append("\"");
 81→        }
 82→        if (priority != null) {
 83→            sb.append(",\"priority\":\"").append(priority).append("\"");
 84→        }
 85→        sb.append("}");
 86→        return sb.toString();
 87→    }
