 89→    private MvcResult createTaskAndReturn(String title, String description, String priority) throws Exception {
 90→        return mockMvc.perform(post("/api/tasks")
 91→                        .header("Authorization", "Bearer " + authToken)
 92→                        .contentType(MediaType.APPLICATION_JSON)
 93→                        .content(taskJson(title, description, priority)))
 94→                .andExpect(status().isCreated())
 95→                .andReturn();
 96→    }
