 98→    private Long createTaskGetId(String title, String description, String priority) throws Exception {
 99→        MvcResult result = createTaskAndReturn(title, description, priority);
100→        JsonNode json = objectMapper.readTree(result.getResponse().getContentAsString());
101→        return json.get("id").asLong();
102→    }
